validator price_enforced_spend {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { seller, price_ref }) = datum
    expect Some(ref_input) =
      transaction.find_input(self.reference_inputs, price_ref)
    expect Some(price_data): Option<PriceDatum> =
      ref_input.output.datum
    let paid =
      list.foldr(
        self.outputs,
        0,
        fn(o, acc) {
          if o.address == seller {
            acc + assets.lovelace_of(o.value)
          } else {
            acc
          }
        },
      )
    paid >= price_data.price
  }
}

