validator preserve_lovelace {
  spend(_datum, _redeemer, own_ref, self) {
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    let script_outs = transaction.find_script_outputs(self.outputs, own_ref)
    let in_lovelace = assets.lovelace_of(own_input.output.value)
    // Every continuing output must carry at least the same lovelace
    list.all(
      script_outs,
      fn(o) { assets.lovelace_of(o.value) >= in_lovelace },
    )
  }
}

