pub type AllowlistDatum =
  List<VerificationKeyHash>

fn find_allowlist(ref_inputs, registry_address: Address) -> AllowlistDatum {
  let ref_input =
    list.find(
      ref_inputs,
      fn(i) { i.output.address == registry_address },
    )
  expect Some(input) = ref_input
  expect Some(data) = input.output.datum
  expect allowlist: AllowlistDatum = data
  allowlist
}

